const rows = $input.all();
const stats = {
  pending: 0,
  resolved: 0,
  discarded: 0,
  total: 0
};

rows.forEach(row => {
  const s = row.json.status;
  const c = parseInt(row.json.count);
  if (stats.hasOwnProperty(s)) stats[s] = c;
  stats.total += c;
});

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      pending_count: stats.pending,
      resolved_count: stats.resolved,
      discarded_count: stats.discarded,
      total_items: stats.total
    },
    _meta: {
      source: 'DLQ_02_Get_Status',
      timestamp: new Date().toISOString(),
      workflow_id: $workflow.id
    }
  }
}];
